#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        double value; char in, out;
        if (scanf("%lf %c %c", &value, &in, &out) != 3) break;
        double result;
        if (in == out) result = value;
        else if (in == 'C' && out == 'F') result = value * 9.0 / 5.0 + 32.0;
        else if (in == 'F' && out == 'C') result = (value - 32.0) * 5.0 / 9.0;
        else result = value; // safety, should not happen
        printf("%.2f\n", result);
    }
    return 0;
}

