import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            double value = Double.parseDouble(st.nextToken());
            char in = st.nextToken().charAt(0);
            char out = st.nextToken().charAt(0);
            double result;
            if (in == out) result = value;
            else if (in == 'C' && out == 'F') result = value * 9.0 / 5.0 + 32.0;
            else if (in == 'F' && out == 'C') result = (value - 32.0) * 5.0 / 9.0;
            else result = value; // safety
            sb.append(String.format(java.util.Locale.US, "%.2f", result)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

