import sys

def convert_temperature(value: float, input_scale: str, output_scale: str) -> float:
    """Convert temperature between Celsius and Fahrenheit.
    Returns the result rounded to two decimal places.
    """
    if input_scale == output_scale:
        return round(value, 2)
    if input_scale == 'C' and output_scale == 'F':
        return round(value * 9.0 / 5.0 + 32.0, 2)
    if input_scale == 'F' and output_scale == 'C':
        return round((value - 32.0) * 5.0 / 9.0, 2)
    raise ValueError('Invalid scale characters')

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    out_lines = []
    for i in range(1, t + 1):
        parts = data[i].split()
        val = float(parts[0])
        inp = parts[1]
        out = parts[2]
        res = convert_temperature(val, inp, out)
        out_lines.append(f"{res:.2f}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

